import{o as e,c as a,a as i}from"./app.6b13adad.js";const t='{"title":"Files and Operations","description":"","frontmatter":{},"headers":[{"level":2,"title":"Files","slug":"files"},{"level":2,"title":"Operations","slug":"operations"},{"level":3,"title":"Split \\"project\\" IFCs","slug":"split-project-ifcs"},{"level":3,"title":"Generate Designs","slug":"generate-designs"},{"level":3,"title":"Detail Scanning","slug":"detail-scanning"},{"level":3,"title":"Prepare Viewer","slug":"prepare-viewer"}],"relativePath":"operations.md","lastUpdated":1636623464571}',s={},l=[i('<h1 id="files-and-operations"><a class="header-anchor" href="#files-and-operations" aria-hidden="true">#</a> Files and Operations</h1><p><div class="table-of-contents"><ul><li><a href="#files">Files</a></li><li><a href="#operations">Operations</a><ul><li><a href="#split-project-ifcs">Split &quot;project&quot; IFCs</a></li><li><a href="#generate-designs">Generate Designs</a></li><li><a href="#detail-scanning">Detail Scanning</a></li><li><a href="#prepare-viewer">Prepare Viewer</a></li></ul></li></ul></div></p><h2 id="files"><a class="header-anchor" href="#files" aria-hidden="true">#</a> Files</h2><p>There are 4 file categories: ifc, drawings, details and docs.</p><ul><li>IFC: Used for 3D viewer, BoMs, machine files. System understands IFCs by a proper &quot;IFC Parsing Setup&quot;. IFCs need filenames such as &quot;PANEL_NAME.ifc&quot;. Example: &quot;PNL30-25.ifc&quot;.</li></ul><div class="info custom-block"><p class="custom-block-title">Full Project IFCs</p><p>You can also upload full project IFCs and the system can split them. Just a filename starting with &quot;Project&quot; is needed. Example: &quot;Project OlaraAvenue15.ifc&quot;.</p></div><ul><li><p>Drawings: .pdf file format. They are shown in the viewer. Drawings are expected to have filenames such as &quot;Merk PANEL_NAME - DRAWING_NUMBER - DRAWING_TEXT.pdf&quot;. Example: &quot;Merk PNL30-25 - 1 - Zone 0 MAIN VIEW.pdf&quot;.</p></li><li><p>Details and documentation: .pdf file format. Also shown in the viewer. Details need filenames such as &quot;DETAIL_NUMBER.pdf&quot;. Example: &quot;V-12.pdf&quot;.</p></li></ul><h2 id="operations"><a class="header-anchor" href="#operations" aria-hidden="true">#</a> Operations</h2><p>Once project files are uploaded, the user can perform several operations:</p><h3 id="split-project-ifcs"><a class="header-anchor" href="#split-project-ifcs" aria-hidden="true">#</a> Split &quot;project&quot; IFCs</h3><p>If there are full project IFCs, a splitting process is accomplished. Each unique panel will result in a new IFC file. Those files can be downloaded also.</p><p>Remember that files with a filename starting with &quot;Project&quot; will be detected as project IFCs.</p><div class="warning custom-block"><p class="custom-block-title">Designs</p><p>Split IFC operation will not create &quot;designs&quot;.</p></div><h3 id="generate-designs"><a class="header-anchor" href="#generate-designs" aria-hidden="true">#</a> Generate Designs</h3><p>The system collects all the drawings, and panel IFCs and creates &quot;design&quot; objects.</p><ul><li><p>A list of design names is built based on IFC filenames and drawings filenames.</p></li><li><p>All the docs are linked to the design, so they are always available.</p></li></ul><h3 id="detail-scanning"><a class="header-anchor" href="#detail-scanning" aria-hidden="true">#</a> Detail Scanning</h3><ul><li><p>Drawings are scanned to find detail names. Found detail names are linked to the design.</p></li><li><p>IFCs are scanned looking for detail names. Found names are linked to the design.</p></li></ul><h3 id="prepare-viewer"><a class="header-anchor" href="#prepare-viewer" aria-hidden="true">#</a> Prepare Viewer</h3><ul><li><p>IFC geometry is analyzed to find rotation&amp;traslation matrices (orientation of the panel in the world coordinates system).</p></li><li><p>Each part of the IFC will be analyzed, generating drawings and metadata which is saved in the database. This database table will bring fast access to the information when the user clicks on a part in the 3D viewer.</p></li><li><p>Drawings are only generated for &quot;wood&quot; and &quot;plate&quot; elements. So, if you don&#39;t have a good IFC Parsing Setup, you may find your panel with some missing drawings.</p></li></ul>',20)];s.render=function(i,t,s,n,r,o){return e(),a("div",null,l)};export{t as __pageData,s as default};
